<?php
namespace App\Filament\Resources; use App\Filament\Resources\CustomerMeetingResource\Pages; use App\Modules\CustomerMeeting\Models\CustomerMeeting; use App\Filament\Support\AdminUploads; use Filament\Forms; use Filament\Forms\Form; use Filament\Resources\Resource; use Filament\Tables; use Filament\Tables\Table;
class CustomerMeetingResource extends Resource { protected static ?string $model=CustomerMeeting::class; protected static ?string $navigationIcon='heroicon-o-user-group'; protected static ?string $navigationGroup='Hoạt động bán hàng'; protected static ?string $modelLabel='Gặp khách'; protected static ?string $pluralModelLabel='Gặp khách'; public static function form(Form $form): Form { return $form->schema([Forms\Components\Select::make('user_id')->label('Nhân viên')->relationship('user','name', function (\Illuminate\Database\Eloquent\Builder $query) { $currentUser = auth()->user(); if (!$currentUser) return $query; $query->where('id', '!=', $currentUser->id)->where('role', '!=', \App\Modules\Auth\Models\Enums\UserRole::BUYER->value)->where('role', '!=', \App\Modules\Auth\Models\Enums\UserRole::SUPER_ADMIN->value)->whereNotNull('job_position_id'); if ($currentUser->role !== \App\Modules\Auth\Models\Enums\UserRole::SUPER_ADMIN) { $query->where('role', '<=', $currentUser->role->value); } if ($currentUser->role === \App\Modules\Auth\Models\Enums\UserRole::DIRECTOR && $currentUser->branch_id) { $query->where('branch_id', $currentUser->branch_id); } if ($currentUser->role === \App\Modules\Auth\Models\Enums\UserRole::MANAGER && $currentUser->department_id) { $query->where('department_id', $currentUser->department_id); } return $query; })->searchable()->preload()->required(), Forms\Components\Select::make('project_id')->label('Khu đất')->relationship('project','name')->searchable()->preload()->required(), Forms\Components\TextInput::make('customer_name')->label('Tên khách')->required(), Forms\Components\TextInput::make('customer_phone')->label('SĐT khách')->required(), Forms\Components\TextInput::make('latitude')->label('Vĩ độ')->numeric(), Forms\Components\TextInput::make('longitude')->label('Kinh độ')->numeric(), AdminUploads::image('image_path', 'Minh chứng', 'admin/customer-meetings')->columnSpanFull()])->columns(2); } public static function table(Table $table): Table { return $table->columns([Tables\Columns\TextColumn::make('user.name')->label('Nhân viên'), Tables\Columns\TextColumn::make('project.name')->label('Khu đất'), Tables\Columns\TextColumn::make('customer_name')->label('Khách'), Tables\Columns\TextColumn::make('created_at')->label('Thời gian')->dateTime('d/m/Y H:i')])->actions([Tables\Actions\EditAction::make(),Tables\Actions\DeleteAction::make()]); } public static function getPages(): array { return ['index'=>Pages\ListCustomerMeetings::route('/'),'create'=>Pages\CreateCustomerMeeting::route('/create'),'edit'=>Pages\EditCustomerMeeting::route('/{record}/edit')]; } }
